B.ape=new A.pO(B.R7,"analiz","Analiz","Test sonu\xe7lar\u0131n\u0131n uzman g\xf6z\xfcyle de\u011ferlendirildi\u011fi, ki\u015finin temel miza\xe7 yap\u0131s\u0131n\u0131 b\xfct\xfcn\xfcyle ortaya koyan profesyonel analiz.","Temel tip, kanat etkisi ve alt tip bir arada de\u011ferlendirilerek ki\u015fiye \xf6zel i\xe7g\xf6r\xfcler sunulur.")
