B.apc=new A.pO(B.QL,"raporlama","Raporlama","Analiz sonu\xe7lar\u0131n\u0131n kapsaml\u0131 ve okunabilir bi\xe7imde sunuldu\u011fu, ki\u015fisel geli\u015fim yolculu\u011funa rehberlik eden yaz\u0131l\u0131 raporlar.","G\xfc\xe7l\xfc y\xf6nler, geli\u015fim alanlar\u0131 ve \xf6nerilen ad\u0131mlar\u0131 i\xe7eren detayl\u0131 raporlar dijital veya bas\u0131l\u0131 olarak teslim edilir.")
