B.ant=new A.pA("Enneagram nedir?","Enneagram, insan do\u011fas\u0131n\u0131n dokuz temel ki\u015filik tipi oldu\u011funu \xf6ne s\xfcren bir ki\u015filik tipolojisidir. Ki\u015finin do\u011fu\u015ftan sahip oldu\u011fu miza\xe7 tipine ba\u011fl\u0131 olarak ortaya \xe7\u0131kan ki\u015filik \xf6zelliklerini ortaya koyan bir haritad\u0131r. Ayn\u0131 zamanda dokuz t\xfcr\xfcn birbiriyle ili\u015fkili oldu\u011fu yollar\u0131 g\xf6steren bir sembold\xfcr.")
B.anr=new A.pA("Enneagram ne i\u015fe yarar? Bana nas\u0131l yard\u0131mc\u0131 olabilir?",'Bir kendini tan\u0131ma kayna\u011f\u0131 olarak son derece yararl\u0131d\u0131r; \xe7\xfcnk\xfc ki\u015fili\u011fimizin normalde g\xf6remedi\u011fimiz \xf6zelliklerini ortaya \xe7\u0131karan bir t\xfcr "ayna" g\xf6revi g\xf6r\xfcr. Al\u0131\u015fkanl\u0131k \xf6r\xfcnt\xfclerimizi netlikle g\xf6rmek \u2014 ne yapt\u0131\u011f\u0131m\u0131z\u0131 ve neden yapt\u0131\u011f\u0131m\u0131z\u0131 \u2014 \xf6zg\xfcrl\xfc\u011f\xfcm\xfcz\xfcn anahtar\u0131d\u0131r.')
B.anv=new A.pA("Miza\xe7 tipimi nas\u0131l tespit edebilirim?","Baz\u0131 insanlar tipini an\u0131nda tan\u0131r, \xe7o\u011fu i\xe7in biraz daha uzun s\xfcrer. Bilka Enneagram testini \xe7\xf6zmek, at\xf6lyelere kat\u0131lmak, yak\u0131n \xe7evreden geri bildirim almak ve kitap okumak s\xfcreci kolayla\u015ft\u0131r\u0131r.")
B.ans=new A.pA("Miza\xe7 tipim do\u011fu\u015ftan m\u0131, sonradan m\u0131 ortaya \xe7\u0131k\u0131yor?","Her birimiz, hayat\u0131m\u0131z boyunca sabit kalan tek bir miza\xe7 tipine sahip olarak do\u011far\u0131z. \xc7evresel etkiyle olu\u015fmaz ama \xe7evreden etkilenir ve geli\u015fim g\xf6sterir. Ki\u015filik yap\u0131m\u0131z, \xe7evresel fakt\xf6rlerle birlikte miza\xe7 yap\u0131m\u0131z\u0131n ortaya koydu\u011fu duygu, d\xfc\u015f\xfcnce ve davran\u0131\u015f b\xfct\xfcn\xfcd\xfcr.")
B.anu=new A.pA("Bilka Enneagram di\u011fer testlerden nas\u0131l farkl\u0131?","Madde havuzu toplumumuza \xf6zg\xfc k\xfclt\xfcrel ve sosyolojik \xf6zelliklere uygun olarak haz\u0131rlanm\u0131\u015f; binin \xfczerinde uygulay\u0131c\u0131 \xfczerinde denenerek en do\u011fru sonu\xe7 veren maddeler se\xe7ilmi\u015ftir. Akademik literat\xfcre kaynak niteli\u011findeki bilimsel makaleye dayan\u0131r.")
B.a__=s([B.ant,B.anr,B.anv,B.ans,B.anu],A.ak("v<pA>"))
