B.Yt=s(["Disiplinli","\u0130lkeli","Rasyonel","Sorumluluk sahibi"],t.s)
B.ajc=new A.jj(B.Yt,"Do\u011fru ve d\xfcr\xfcst olmak","Yozla\u015fm\u0131\u015f veya hatal\u0131 g\xf6r\xfcnmek",'Reformcular ideal bir d\xfcnyan\u0131n pe\u015findedir. \u0130\xe7 sesleri s\xfcrekli "daha iyisi m\xfcmk\xfcn" der; bu da onlar\u0131 hem motive eder hem de a\u015f\u0131r\u0131 ele\u015ftirelli\u011fe iter.')
B.Xb=s(["S\u0131cak","C\xf6mert","Empatik","Yard\u0131mla\u015fan"],t.s)
B.aj8=new A.jj(B.Xb,"Sevilmek ve de\u011fer g\xf6rmek","\u0130stenmemek, gereksiz g\xf6r\xfclmek","Yard\u0131mseverler ba\u015fkalar\u0131n\u0131n ihtiyac\u0131n\u0131 kendi ihtiya\xe7lar\u0131ndan \xf6nce duyarlar. Sahip olduklar\u0131 en b\xfcy\xfck g\xfcc\xfc olan ilgi, s\u0131n\u0131r\u0131 olmad\u0131\u011f\u0131nda yorgunlu\u011fa d\xf6n\xfc\u015febilir.")
B.TN=s(["H\u0131rsl\u0131","Adapte olan","Hedef odakl\u0131","Etkileyici"],t.s)
B.ajf=new A.jj(B.TN,"De\u011ferli ve ba\u015far\u0131l\u0131 hissetmek","Ba\u015far\u0131s\u0131z olmak, g\xf6r\xfcnmez kalmak","Ba\u015far\u0131 Odakl\u0131lar imaja ve sonuca duyarl\u0131d\u0131r. As\u0131l g\xfc\xe7, d\u0131\u015f ba\u015far\u0131dan i\xe7sel yetkinli\u011fe d\xf6nen yolculuktad\u0131r.")
B.ZX=s(["\xd6zg\xfcn","Duygusal derin","Yarat\u0131c\u0131","Sezgisel"],t.s)
B.ajb=new A.jj(B.ZX,"Kendileri olmak, anlam bulmak","\xd6nemsiz veya s\u0131radan hissetmek","Bireyciler duygular\u0131n derin sular\u0131nda ya\u015far. Bu derinlik hem sanat\u0131n hem de melankolinin kayna\u011f\u0131d\u0131r.")
B.Vq=s(["Analitik","Merakl\u0131","Ba\u011f\u0131ms\u0131z","Sezgisel"],t.s)
B.aja=new A.jj(B.Vq,"Yetkin ve donan\u0131ml\u0131 olmak","\u0130\u015fe yaramaz, kapasitesiz kalmak","Ara\u015ft\u0131rmac\u0131lar d\xfcnyay\u0131 anlamak i\xe7in geri \xe7ekilirler. Bilgi, hayat\u0131 y\xf6netmenin g\xfcvenli yoludur \u2014 ta ki payla\u015fman\u0131n da bir bilgelik oldu\u011fu g\xf6r\xfclene kadar.")
B.a_7=s(["G\xfcvenilir","Sad\u0131k","Tedbirli","\u0130\u015fbirlik\xe7i"],t.s)
B.aj7=new A.jj(B.a_7,"G\xfcvende olmak, desteklenmek","Yaln\u0131z ve haz\u0131rl\u0131ks\u0131z yakalanmak","Sad\u0131klar olas\u0131 riskleri \xf6nceden g\xf6r\xfcr ve haz\u0131rl\u0131kl\u0131 olmay\u0131 sever. \u015e\xfcphe ile cesaret aras\u0131nda sal\u0131nan i\xe7 d\xfcnyalar\u0131 onlar\u0131 sa\u011flam dostlar yapar.")
B.a_r=s(["Co\u015fkulu","H\u0131zl\u0131","Macerac\u0131","\u0130yimser"],t.s)
B.ajd=new A.jj(B.a_r,"Mutlu ve \xf6zg\xfcr olmak","Ac\u0131, s\u0131k\u0131\u015fm\u0131\u015fl\u0131k, eksik kalmak","Merakl\u0131lar hayat\u0131 bir olas\u0131l\u0131klar bah\xe7esi gibi ya\u015far. As\u0131l ustal\u0131k, derinle\u015fmenin de bir t\xfcr \xf6zg\xfcrl\xfck oldu\u011funu fark etmektir.")
B.Vd=s(["G\xfc\xe7l\xfc","Kararl\u0131","Koruyucu","Do\u011frudan"],t.s)
B.aje=new A.jj(B.Vd,"Kendi hayat\u0131n\u0131n sahibi olmak","Kontrol\xfc kaybetmek, zay\u0131f g\xf6r\xfcnmek","Meydan Okuyanlar d\xfcnyay\u0131 g\xfc\xe7 dengesi olarak okur. Yumu\u015fakl\u0131\u011fa izin verdiklerinde ger\xe7ek liderlik ortaya \xe7\u0131kar.")
B.a2o=s(["Kabul edici","Sakin","Uzla\u015ft\u0131ran","Sab\u0131rl\u0131"],t.s)
B.aj9=new A.jj(B.a2o,"\u0130\xe7 ve d\u0131\u015f bar\u0131\u015f\u0131 korumak","Kopu\u015f, \xe7at\u0131\u015fma, kaybolma","Bar\u0131\u015f\xe7\u0131llar herkesi duyabilen nadir bir denge ta\u015f\u0131r. As\u0131l uyan\u0131\u015f, kendi sesini de duyduklar\u0131nda ba\u015flar.")
