B.T1=new A.rh("\xc7erez Politikas\u0131",null)
B.SB=new A.ci("\xc7erez Politikas\u0131","Bu politika, Bilka Enneagram web sitesinin \xe7erez (cookie) kullan\u0131m\u0131na ili\u015fkin bilgileri i\xe7ermektedir. Sitemizi kullanmaya devam ederek bu politikay\u0131 kabul etmi\u015f say\u0131l\u0131rs\u0131n\u0131z.","Son g\xfcncelleme: Ocak 2025",!0)
B.SH=new A.ci("1. \xc7erez Nedir?","\xc7erezler, bir web sitesini ziyaret etti\u011finizde taray\u0131c\u0131n\u0131za kaydedilen k\xfc\xe7\xfck metin dosyalar\u0131d\u0131r. Bu dosyalar, sonraki ziyaretlerinizde sizi tan\u0131mam\u0131za ve deneyiminizi ki\u015fiselle\u015ftirmemize yard\u0131mc\u0131 olur.",null,!1)
B.Sw=new A.ci("2. Kulland\u0131\u011f\u0131m\u0131z \xc7erez T\xfcrleri","Sitemizde a\u015fa\u011f\u0131daki \xe7erez t\xfcrleri kullan\u0131lmaktad\u0131r:\n\n\u2022 Zorunlu \xc7erezler: Sitenin temel i\u015flevlerini yerine getirebilmesi i\xe7in gereklidir. Bu \xe7erezler devre d\u0131\u015f\u0131 b\u0131rak\u0131lamaz.\n\n\u2022 \u0130\u015flevsel \xc7erezler: Dil tercihiniz gibi ayarlar\u0131n\u0131z\u0131 hat\u0131rlamak i\xe7in kullan\u0131l\u0131r.\n\n\u2022 Analitik \xc7erezler: Site kullan\u0131m\u0131n\u0131 anlamam\u0131za ve iyile\u015ftirmemize yard\u0131mc\u0131 olan istatistiksel veriler toplar. Kimli\u011finizi do\u011frudan a\xe7\u0131klamaz.\n\n\u2022 Oturum \xc7erezleri: Taray\u0131c\u0131 kapat\u0131ld\u0131\u011f\u0131nda otomatik olarak silinen ge\xe7ici \xe7erezlerdir.",null,!1)
B.Sx=new A.ci("3. \xc7erezlerin Kullan\u0131m Amac\u0131","\xc7erezleri \u015fu ama\xe7larla kullan\u0131yoruz:\n\n\u2022 Oturum g\xfcvenli\u011fini sa\u011flamak\n\u2022 Test s\xfcrecinde ilerlemenizi ge\xe7ici olarak kaydetmek\n\u2022 Sitenin performans\u0131n\u0131 \xf6l\xe7mek ve iyile\u015ftirmek\n\u2022 Kullan\u0131c\u0131 deneyimini ki\u015fiselle\u015ftirmek",null,!1)
B.SO=new A.ci("4. \xc7erez Y\xf6netimi","Taray\u0131c\u0131 ayarlar\u0131n\u0131zdan \xe7erezleri y\xf6netebilirsiniz:\n\n\u2022 T\xfcm \xe7erezleri engelleyebilirsiniz (bu durumda baz\u0131 site \xf6zellikleri \xe7al\u0131\u015fmayabilir)\n\u2022 Mevcut \xe7erezleri silebilirsiniz\n\u2022 Belirli sitelerden gelen \xe7erezleri kabul edebilir veya reddedebilirsiniz\n\nPop\xfcler taray\u0131c\u0131larda \xe7erez ayarlar\u0131: Chrome \u2192 Ayarlar \u2192 Gizlilik; Firefox \u2192 Tercihler \u2192 Gizlilik; Safari \u2192 Tercihler \u2192 Gizlilik.",null,!1)
B.SP=new A.ci("5. \xdc\xe7\xfcnc\xfc Taraf \xc7erezleri","Sitemiz, analitik ama\xe7larla s\u0131n\u0131rl\u0131 \xfc\xe7\xfcnc\xfc taraf hizmetleri kullanabilir. Bu hizmetler kendi gizlilik politikalar\u0131 kapsam\u0131nda \xe7erez olu\u015fturabilir. S\xf6z konusu \xe7erezler \xfczerinde do\u011frudan kontrol\xfcm\xfcz bulunmamaktad\u0131r.",null,!1)
B.SD=new A.ci("6. Politika G\xfcncellemeleri","\xc7erez politikam\u0131z zaman zaman g\xfcncellenebilir. De\u011fi\u015fiklikler bu sayfada yay\u0131mlanarak y\xfcr\xfcrl\xfc\u011fe girer. D\xfczenli olarak kontrol etmenizi \xf6neririz.",null,!1)
B.SU=new A.ci("7. \u0130leti\u015fim","\xc7erez politikam\u0131zla ilgili sorular\u0131n\u0131z i\xe7in:\n\nBilka Enneagram\nE-posta: info@bilkaenneagram.com.tr\nTelefon: +90 (555) 000 00 00",null,!1)
