B.T2=new A.rh("KVKK Ayd\u0131nlatma Metni",null)
B.T0=new A.ci("KVKK Ayd\u0131nlatma Metni","6698 say\u0131l\u0131 Ki\u015fisel Verilerin Korunmas\u0131 Kanunu'nun (KVKK) 10. maddesi uyar\u0131nca veri sorumlusu s\u0131fat\u0131yla haz\u0131rlanan bu ayd\u0131nlatma metni; Bilka Enneagram web sitesini ve test hizmetini kullanan ki\u015filere, ki\u015fisel verilerinin nas\u0131l topland\u0131\u011f\u0131, i\u015flendi\u011fi ve korundu\u011fu hakk\u0131nda bilgi vermek amac\u0131yla d\xfczenlenmi\u015ftir.","Son g\xfcncelleme: Ocak 2025",!0)
B.SA=new A.ci("1. Veri Sorumlusu","Veri Sorumlusu: Bilka Enneagram\nE-posta: info@bilkaenneagram.com.tr\nTelefon: +90 (555) 000 00 00\n\nKi\u015fisel verileriniz, yukar\u0131da belirtilen veri sorumlusu taraf\u0131ndan KVKK kapsam\u0131nda i\u015flenmektedir.",null,!1)
B.Sv=new A.ci("2. \u0130\u015flenen Ki\u015fisel Veriler","Hizmetlerimiz arac\u0131l\u0131\u011f\u0131yla a\u015fa\u011f\u0131daki kategorilerdeki ki\u015fisel verileriniz toplanmakta ve i\u015flenmektedir:\n\n\u2022 Kimlik Verileri: Ad, soyad, do\u011fum tarihi\n\u2022 \u0130leti\u015fim Verileri: E-posta adresi, telefon numaras\u0131\n\u2022 Test ve Analiz Verileri: Enneagram testi cevaplar\u0131, ki\u015filik tipi sonu\xe7lar\u0131, miza\xe7 analizi raporu\n\u2022 \u0130\u015flem G\xfcvenli\u011fi Verileri: IP adresi, oturum bilgisi, taray\u0131c\u0131 t\xfcr\xfc\n\u2022 Onay ve \u0130zin Kay\u0131tlar\u0131: Gizlilik politikas\u0131 ve KVKK onay tarihleri",null,!1)
B.Sy=new A.ci("3. Ki\u015fisel Verilerin \u0130\u015flenme Ama\xe7lar\u0131","Toplanan ki\u015fisel verileriniz a\u015fa\u011f\u0131daki ama\xe7lar do\u011frultusunda i\u015flenmektedir:\n\n\u2022 Enneagram testinin y\xfcr\xfct\xfclmesi ve ki\u015filik analizi sonu\xe7lar\u0131n\u0131n hesaplanmas\u0131\n\u2022 Test raporunun e-posta yoluyla iletilmesi\n\u2022 Miza\xe7 dan\u0131\u015fmanl\u0131\u011f\u0131 ve bireysel seans hizmetlerinin sunulmas\u0131\n\u2022 \u0130leti\u015fim taleplerine yan\u0131t verilmesi\n\u2022 Hizmet kalitesinin de\u011ferlendirilmesi ve iyile\u015ftirilmesi\n\u2022 Yasal y\xfck\xfcml\xfcl\xfcklerin yerine getirilmesi ve yetkili kurum taleplerine kar\u015f\u0131l\u0131k verilmesi",null,!1)
B.SX=new A.ci("4. Hukuki \u0130\u015fleme Dayana\u011f\u0131","Ki\u015fisel verileriniz KVKK'n\u0131n 5. ve 6. maddeleri kapsam\u0131nda \u015fu hukuki dayanaklar \xe7er\xe7evesinde i\u015flenmektedir:\n\n\u2022 A\xe7\u0131k R\u0131za (m. 5/1): Test ve ki\u015filik analizi verilerinin i\u015flenmesi i\xe7in\n\u2022 S\xf6zle\u015fmenin Kurulmas\u0131 ve \u0130fas\u0131 (m. 5/2-c): Hizmet ili\u015fkisinin yerine getirilmesi i\xe7in\n\u2022 Me\u015fru Menfaat (m. 5/2-f): Hizmet kalitesinin geli\u015ftirilmesine y\xf6nelik istatistiksel analizler i\xe7in\n\u2022 Hukuki Y\xfck\xfcml\xfcl\xfck (m. 5/2-\xe7): Yasal saklama ve raporlama y\xfck\xfcml\xfcl\xfckleri i\xe7in",null,!1)
B.T_=new A.ci("5. Ki\u015fisel Verilerin Aktar\u0131lmas\u0131","Ki\u015fisel verileriniz, a\u015fa\u011f\u0131daki durumlar d\u0131\u015f\u0131nda \xfc\xe7\xfcnc\xfc taraflarla payla\u015f\u0131lmaz:\n\n\u2022 Yasal zorunluluk kapsam\u0131nda yetkili kamu kurum ve kurulu\u015flar\u0131na\n\u2022 Hizmetin teknik altyap\u0131s\u0131n\u0131 sa\u011flayan ve KVKK uyumlu gizlilik s\xf6zle\u015fmesi imzalam\u0131\u015f tedarik\xe7ilere, yaln\u0131zca hizmetin ifas\u0131 i\xe7in zorunlu olan \xf6l\xe7\xfcde\n\nKi\u015fisel verileriniz kural olarak yurt d\u0131\u015f\u0131na aktar\u0131lmamaktad\u0131r. Zorunlu olmas\u0131 halinde yaln\u0131zca yeterli koruma seviyesine sahip veya taahh\xfctname imzalam\u0131\u015f \xfclkelerle aktar\u0131m yap\u0131l\u0131r.",null,!1)
B.SE=new A.ci("6. Ki\u015fisel Verilerin Saklanma S\xfcresi","Ki\u015fisel verileriniz, hizmet ili\u015fkisinin sona ermesinin ard\u0131ndan ilgili mevzuatta \xf6ng\xf6r\xfclen s\xfcreler ve Bilka Enneagram'\u0131n me\u015fru menfaatleri do\u011frultusunda en fazla 3 (\xfc\xe7) y\u0131l s\xfcreyle muhafaza edilir. Bu s\xfcrenin dolmas\u0131n\u0131n ard\u0131ndan verileriniz; g\xfcvenli imha, silme veya anonimle\u015ftirme y\xf6ntemlerinden biri ile kal\u0131c\u0131 olarak ortadan kald\u0131r\u0131l\u0131r.",null,!1)
B.SK=new A.ci("7. KVKK'dan Do\u011fan Haklar\u0131n\u0131z","KVKK'n\u0131n 11. maddesi uyar\u0131nca veri sahibi s\u0131fat\u0131yla a\u015fa\u011f\u0131daki haklara sahipsiniz:\n\n\u2022 Ki\u015fisel verilerinizin i\u015flenip i\u015flenmedi\u011fini \xf6\u011frenme\n\u2022 \u0130\u015flenmi\u015fse buna ili\u015fkin bilgi talep etme\n\u2022 \u0130\u015flenme amac\u0131n\u0131 ve bu amaca uygun kullan\u0131l\u0131p kullan\u0131lmad\u0131\u011f\u0131n\u0131 \xf6\u011frenme\n\u2022 Yurt i\xe7inde veya yurt d\u0131\u015f\u0131nda aktar\u0131ld\u0131\u011f\u0131 \xfc\xe7\xfcnc\xfc ki\u015fileri bilme\n\u2022 Eksik veya yanl\u0131\u015f i\u015flenen verilerin d\xfczeltilmesini isteme\n\u2022 Amac\u0131n ortadan kalkmas\u0131 halinde silinmesini veya yok edilmesini talep etme\n\u2022 D\xfczeltme ve silme i\u015flemlerinin, aktar\u0131lan taraflara bildirilmesini isteme\n\u2022 Otomatik sistemler arac\u0131l\u0131\u011f\u0131yla analiz sonucunda aleyhinize do\u011fan karar\u0131n itiraz\u0131n\u0131 yapma\n\u2022 Kanuna ayk\u0131r\u0131 i\u015fleme nedeniyle u\u011fran\u0131lan zarar\u0131n tazminini talep etme",null,!1)
B.Sz=new A.ci("8. Ba\u015fvuru Y\xf6ntemi","Yukar\u0131da say\u0131lan haklar\u0131n\u0131z\u0131 kullanmak i\xe7in kimli\u011finizi do\u011frulay\u0131c\u0131 belgelerle birlikte a\u015fa\u011f\u0131daki kanallar arac\u0131l\u0131\u011f\u0131yla Bilka Enneagram'a ba\u015fvurabilirsiniz:\n\nBilka Enneagram\nE-posta: info@bilkaenneagram.com.tr\nTelefon: +90 (555) 000 00 00\n\nBa\u015fvurunuz, KVKK'n\u0131n 13. maddesi gere\u011fince en ge\xe7 30 (otuz) g\xfcn i\xe7inde \xfccretsiz olarak yan\u0131tlanacakt\u0131r. Talebin ayr\u0131ca bir maliyet gerektirmesi durumunda Ki\u015fisel Verileri Koruma Kurulu taraf\u0131ndan belirlenen tarifeye g\xf6re \xfccret al\u0131nabilir.",null,!1)
