B.abc=new A.lh("9 Miza\xe7 Tipi","9 temel aray\u0131\u015f, ","9 miza\xe7"," tipi.","Enneagram'a g\xf6re insanlar en temelde 9 nefs kategorisine ayr\u0131l\u0131r. Bu bir etiketleme de\u011fil, var olan\u0131 en nesnel haliyle ortaya koymakt\u0131r.",B.bR,null)
B.abd=new A.lh("Hakk\u0131m\u0131zda","D\xfcnyada ender rastlanan bir ","akademik"," \xe7al\u0131\u015fma.","Bilka Enneagram, ki\u015filik tiplerini en nesnel ve g\xfcvenilir \u015fekilde ortaya koymay\u0131 hedefleyen \xf6zg\xfcn bir test sistemidir.",B.bR,null)
B.abe=new A.lh("\u0130leti\u015fim","Bizimle ileti\u015fime ","ge\xe7in.",null,"Test hakk\u0131nda sorular\u0131n\u0131z i\xe7in veya miza\xe7 dan\u0131\u015fmanl\u0131\u011f\u0131 randevusu almak i\xe7in bize ula\u015fabilirsiniz.",B.bR,null)
B.abf=new A.lh("Neden Bilka Enneagram?","Akademik g\xfcvenilirlik,\n","k\xfclt\xfcrel"," duyarl\u0131l\u0131k.","Testin her maddesi, binin \xfczerinde kat\u0131l\u0131mc\u0131yla denenerek en y\xfcksek do\u011fruluk skorunu elde eden sorulardan se\xe7ilmi\u015ftir.",B.bR,null)
