B.anM=new A.nr("Testin \xd6zg\xfcnl\xfc\u011f\xfc","Bilka Enneagram testi d\xfcnyada ender rastlanan \xf6zelliklere sahip akademik bir \xe7al\u0131\u015fmad\u0131r. Haz\u0131rlanma a\u015famas\u0131nda miza\xe7 \xf6r\xfcnt\xfclerini olu\u015fturan maddeler, toplumumuza \xf6zg\xfc k\xfclt\xfcrel ve sosyolojik \xf6zelliklere uygun olarak haz\u0131rlanm\u0131\u015f havuzdan; en do\u011fru sonu\xe7 veren maddeler binin \xfczerinde uygulay\u0131c\u0131 \xfczerinde denenerek se\xe7ilmi\u015ftir.",null)
B.anN=new A.nr("Enneagram ve Ki\u015filik",'Enneagram en bilinen haliyle bir ki\u015filik tipleri sistemi; bilimsel ad\u0131yla "Ki\u015filik Tipolojisi"dir. \u0130nsan\u0131n f\u0131trat\u0131nda var olan nefs yap\u0131s\u0131nda, aray\u0131\u015flardan kaynaklanan zaaflar vard\u0131r.',null)
B.anO=new A.nr("Dan\u0131\u015fmanl\u0131k Deste\u011fi",'Testi \xe7\xf6zerek miza\xe7 tipinizi tespit ettikten sonra online veya y\xfcz y\xfcze "Miza\xe7 dan\u0131\u015fmanl\u0131\u011f\u0131" alarak bireysel geli\u015fiminizi en do\u011fru \u015fekilde destekleyebilirsiniz.',null)
B.anP=new A.nr("Bilimsel Katk\u0131","\xc7al\u0131\u015fman\u0131n bilimsel makalesi d\xfcnya akademik literat\xfcr\xfcne kaynak niteli\u011fi kazand\u0131r\u0131lmas\u0131 hedeflenerek haz\u0131rlanm\u0131\u015ft\u0131r. Her madde, ilgili mizac\u0131n t\xfcm kanatl\u0131 versiyonlar\u0131na, t\xfcm alt tiplerine ve sa\u011fl\u0131k boyutuna hitap edecek \u015fekilde se\xe7ilmi\u015ftir.",null)
B.anQ=new A.nr("Renkler Metaforu","D\xfcnyada sar\u0131, k\u0131rm\u0131z\u0131 ve mavi olmak \xfczere yaln\u0131zca \xfc\xe7 ana renk vard\u0131r. Her insan nev-i \u015fahs\u0131na m\xfcnhas\u0131r, \xf6zg\xfcn bir ki\u015filiktir.",null)
